-- 0021 — Seed des cadres existants (bootstrap inline)
-- Insère les cadres actuels de la DB locale directement dans border_catalog
-- avec leur PNG encodé en base64 dans `payload`. Pas de dépendance bucket
-- Storage : seed atomique et idempotent, survit aux `db reset`.
-- Sources : `assets/borders/*.png` du repo (pour example) et upload admin
-- antérieur (pour beurk).

-- ═════════════ example (32×32, default) ═════════════

insert into public.border_catalog (
  border_key, title, description, kind, payload,
  image_width, image_height,
  slice_top, slice_right, slice_bottom, slice_left,
  tokens, is_default
) values (
  'example',
  'Exemple',
  'Cadre PNG 32x32 fourni avec l''app pour bootstrap.',
  'png_9slice',
  '',
  32, 32,
  8, 11, 11, 8,
  '{}'::jsonb,
  true
)
on conflict (border_key) do nothing;

-- ═════════════ beurk (200×200, ink frame manuel) ═════════════
-- Cadre dessiné main, encre noire sur fond transparent. Slices 20px
-- partout. bg_insets laissés NULL → app utilise slice/2 = 10px par défaut.

insert into public.border_catalog (
  border_key, title, description, kind, payload,
  image_width, image_height,
  slice_top, slice_right, slice_bottom, slice_left,
  tokens, is_default
) values (
  'beurk',
  'Beurk',
  null,
  'png_9slice',
  '',
  200, 200,
  20, 20, 20, 20,
  '{}'::jsonb,
  false
)
on conflict (border_key) do nothing;
